void solve(int CASE)
{
	ll n; cin >> n;
	var a = vector<ll>(n + 1);
	fa(i, 1, n)cin >> a[i];
	var st = ST<ll>(a, ST<ll>::_gcd);
	var mp = HashMap<ll, ll>();
	fa(i, 1, n) {
		ll now = i, nowgcd = a[i];
		while (now != n + 1) {
			var check = [&](ll mid)->bool {
				return st.queryGCD(i, mid) == nowgcd;
				};
			ll l = now, r = n, ans = now;
			while (l <= r) {
				int mid = l + r >> 1;
				if (check(mid)) {
					l = mid + 1;
					ans = mid;
				}
				else r = mid - 1;
			}
			mp[nowgcd] += ans - now + 1;
			now = ans + 1;
			nowgcd = st.queryGCD(i, now);
		}
	}
	ll q; cin >> q;
	while (q--) {
		ll x; cin >> x;
		cout << mp[x] << endl;
	}
	return;
}
